@font-face {
  font-family: 'Inter V';
  src: url('/fonts/Inter-V.woff2') format('woff2');
  font-weight: 100 900;
  font-style: normal;
  font-display: swap; /* Recommended for body text to prioritize content */
}

@font-face {
  font-family: 'Brand Display';
  src: url('/fonts/BrandDisplay-Bold.woff2') format('woff2');
  font-weight: 700;
  font-style: normal;
  font-display: fallback; /* Short block period, then swap. Good for prominent titles. */
}

/* Example for a less critical, decorative font */
@font-face {
  font-family: 'Decorative Script';
  src: url('/fonts/DecorativeScript.woff2') format('woff2');
  font-weight: 400;
  font-style: normal;
  font-display: optional; /* Font is only loaded if connection is good and cached. */
}
